insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'In a row of 40 candidates, Ravi is 12th from the left. What is his rank from the right?', '40 candidates की row में Ravi left से 12th है। Right से उसका rank क्या है?', 'Right rank = 40 - 12 + 1 = 29. Therefore, answer = 29.', 'For rank from the opposite side, the person''s position is counted in both directions, so add 1 after subtracting from total. Final answer is 29.', 'Right rank = 40 - 12 + 1 = 29। अतः answer = 29।', 'Opposite-side rank में person दोनों sides की counting में शामिल होता है, इसलिए total से subtract करके +1 करते हैं। Final answer 29 है।', 'EASY', array['reasoning','ranking']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '29', '29', true, null, null);
