insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '13', '13', false, 'Copied the left rank as right rank without converting sides.', 'Left rank को right rank में convert किए बिना copy कर दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '57', '57', false, 'Added total and rank, which gives a count beyond the row size.', 'Total और rank add कर दिए, जिससे row size से बाहर count आता है।');
